import os
import logging
from flask import Flask, request, jsonify
import elasticapm
from elasticapm import Client
from elasticapm.contrib.flask import ElasticAPM
import sqlite3
import time

# Initialize Flask app
app = Flask(__name__)

# Configure APM client
apm_client = Client(
    server_url=os.getenv('ELASTIC_APM_SERVER_URL', 'http://localhost:8200'),
    service_name=os.getenv('ELASTIC_APM_SERVICE_NAME', 'python-app'),
    environment=os.getenv('ELASTIC_APM_ENVIRONMENT', 'production'),
    secret_token=os.getenv('ELASTIC_APM_SECRET_TOKEN'),
    server_cert=os.getenv('ELASTIC_APM_SERVER_CERT', ''),
    verify_server_cert=True,
    capture_body='all',
    capture_headers=True,
    instrument=True,
    include_paths=['/api/'],
    exclude_paths=['/health'],
    logging=True,
    log_level=logging.INFO
)

# Initialize Flask APM integration
apm = ElasticAPM(app, client=apm_client)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Database setup
def init_db():
    conn = sqlite3.connect('app.db')
    cursor = conn.cursor()
    cursor.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name TEXT NOT NULL,
            email TEXT UNIQUE NOT NULL
        )
    ''')
    conn.commit()
    conn.close()

# Sample endpoints
@app.route('/health')
def health_check():
    return jsonify({'status': 'healthy'}), 200

@app.route('/api/users', methods=['POST'])
def create_user():
    try:
        data = request.get_json()
        name = data.get('name')
        email = data.get('email')
        
        # Simulate some processing time
        time.sleep(0.1)
        
        conn = sqlite3.connect('app.db')
        cursor = conn.cursor()
        cursor.execute('INSERT INTO users (name, email) VALUES (?, ?)', (name, email))
        conn.commit()
        conn.close()
        
        return jsonify({'message': 'User created successfully'}), 201
        
    except Exception as e:
        logger.error(f"Error creating user: {str(e)}")
        apm_client.capture_exception()
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/api/users', methods=['GET'])
def get_users():
    try:
        # Capture custom span
        with apm_client.capture_span('fetch_users_from_db'):
            conn = sqlite3.connect('app.db')
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users')
            users = cursor.fetchall()
            conn.close()
            
        return jsonify({'users': users}), 200
        
    except Exception as e:
        logger.error(f"Error fetching users: {str(e)}")
        apm_client.capture_exception()
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/api/slow-endpoint', methods=['GET'])
def slow_endpoint():
    try:
        # Simulate slow processing
        time.sleep(2)
        
        # Simulate database query
        with apm_client.capture_span('slow_database_query'):
            conn = sqlite3.connect('app.db')
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM users WHERE id = 1')
            result = cursor.fetchone()
            conn.close()
            
        return jsonify({'result': result}), 200
        
    except Exception as e:
        logger.error(f"Error in slow endpoint: {str(e)}")
        apm_client.capture_exception()
        return jsonify({'error': 'Internal server error'}), 500

# Error handlers
@app.errorhandler(404)
def not_found(error):
    return jsonify({'error': 'Not found'}), 404

@app.errorhandler(500)
def internal_error(error):
    apm_client.capture_exception()
    return jsonify({'error': 'Internal server error'}), 500

